Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class PlatformSpecificTests
{
    // 1. Windows-only: skip on other OSes
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Registry.GetValue(@"HKEY_LOCAL_MACHINE\SOFTWARE\...", "Key", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_ProducesValidOutput()
    {
        var result = GpuRenderer.RenderFrame();
        Assert.IsNotNull(result);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast(TestContext testContext)
    {
        var forecast = await _client.GetForecastAsync(testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Cleanup temp files even on failure
    private string _tempFile = string.Empty;

    [TestInitialize]
    public void Setup()
    {
        _tempFile = Path.GetTempFileName();
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (File.Exists(_tempFile))
            File.Delete(_tempFile);
    }

    [TestMethod]
    public void ProcessFile_WritesExpectedContent()
    {
        FileProcessor.Process(_tempFile);
        var content = File.ReadAllText(_tempFile);
        Assert.Contains("expected", content);
    }
}
```

**Key points:**

| Scenario | Attribute | Min Version |
|---|---|---|
| OS-specific | `[OSCondition(OperatingSystems.Windows)]` | 3.10+ |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` | 3.10+ |
| Flaky retries | `[Retry(3)]` | 3.9+ |
| Guaranteed cleanup | `[TestCleanup]` | any |

- **`[TestCleanup]`** runs after every test regardless of pass/fail, making it ideal for temp file deletion.
- **`[Retry]`** should only be used for genuinely flaky external dependencies — not to mask race conditions or shared state bugs.
- **`[Timeout]`** pairs well with `[Retry]` so a hung call doesn't block all retries. Use `TestContext.CancellationToken` to propagate the timeout into async calls.
